'use client';

import Link from 'next/link';
import { useMemo, useState } from 'react';
import type { ScheduledLessonDto } from '@soenglish/shared-types';
import { BookOpen, Calendar, ChevronRight, Clock, Plus, Search, Users, Video } from 'lucide-react';
import { Button, PageHeader, SurfaceCard } from '../../components/ui';
import {
  activeMockUser,
  canSchedule,
  canView,
  getVisibleProfiles,
  mockUsers,
} from '../../mocks';
import { LessonModal } from '../../features/lesson-modal';
import type { LessonFormState, LessonModalMode } from '../../features/lesson-modal/types';
import { fromLessonFormState } from '../../features/calendar/adapters/lessonCalendarAdapter';
import { hasTimeConflict, isPastSlot } from '../../features/calendar/rules/conflicts';
import { getInitialLessons } from '../../features/calendar/services/lessonCalendarService';
import styles from './page.module.scss';

function toDateString(date: Date): string {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(
    date.getDate(),
  ).padStart(2, '0')}`;
}

const STATUS_OPTIONS: Array<{ value: 'all' | ScheduledLessonDto['status']; label: string }> = [
  { value: 'all', label: 'All' },
  { value: 'planned', label: 'Planned' },
  { value: 'completed', label: 'Done' },
  { value: 'cancelled', label: 'Cancelled' },
];

function statusLabel(status: ScheduledLessonDto['status']) {
  if (status === 'planned') return 'Planned';
  if (status === 'completed') return 'Completed';
  return 'Cancelled';
}

function formatShortDate(isoDate: string) {
  const d = new Date(`${isoDate}T12:00:00`);
  return d.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
}

export default function LessonsPage() {
  const hasAccess = canView('dashboard', activeMockUser.role);

  const [query, setQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | ScheduledLessonDto['status']>('all');
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);

  const visibleLessons = useMemo(
    () =>
      mockScheduledLessons
        .filter((lesson) => {
          if (activeMockUser.role === 'student') return lesson.studentId === activeMockUser.id;
          if (activeMockUser.role === 'teacher') return lesson.teacherId === activeMockUser.id;
          return true;
        })
        .sort((a, b) => `${a.date}T${a.startTime}`.localeCompare(`${b.date}T${b.startTime}`)),
    [],
  );

  const filteredLessons = useMemo(() => {
    const normalizedQuery = query.trim().toLowerCase();
    return visibleLessons.filter((lesson) => {
      const queryMatch =
        normalizedQuery.length === 0 ||
        lesson.title.toLowerCase().includes(normalizedQuery) ||
        lesson.teacherName.toLowerCase().includes(normalizedQuery) ||
        lesson.studentName.toLowerCase().includes(normalizedQuery);
      const statusMatch = statusFilter === 'all' || lesson.status === statusFilter;
      return queryMatch && statusMatch;
    });
  }, [query, statusFilter, visibleLessons]);

  const selectedLesson =
    filteredLessons.find((lesson) => lesson.id === selectedLessonId) ?? filteredLessons[0] ?? null;

  const upcomingCount = useMemo(
    () => visibleLessons.filter((l) => l.status === 'planned').length,
    [visibleLessons],
  );

  if (!hasAccess) return null;

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title="Lessons"
        subtitle="Browse your schedule, open a lesson, or jump to the calendar"
      />

      <div className={styles.workspace}>
        <div className={styles.listColumn}>
          <SurfaceCard className={styles.listPane}>
            <div className={styles.toolbar}>
              <div className={styles.searchWrap}>
                <Search size={18} className={styles.searchIcon} aria-hidden />
                <input
                  type="search"
                  className={styles.searchInput}
                  value={query}
                  onChange={(event) => setQuery(event.target.value)}
                  placeholder="Search title, teacher, or student..."
                  aria-label="Search lessons"
                />
              </div>

              <div className={styles.filterBlock}>
                <span className={styles.filterHeading}>Status</span>
                <div className={styles.chipRow} role="group" aria-label="Filter by status">
                  {STATUS_OPTIONS.map((opt) => (
                    <button
                      key={opt.value}
                      type="button"
                      className={`${styles.chip} ${statusFilter === opt.value ? styles.chipActive : ''}`}
                      onClick={() => setStatusFilter(opt.value)}
                      aria-pressed={statusFilter === opt.value}
                    >
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>

              <div className={styles.toolbarMeta}>
                <span className={styles.livePill}>
                  <span className={styles.liveDot} aria-hidden />
                  {upcomingCount} upcoming
                </span>
                <span className={styles.countMuted}>
                  Showing {filteredLessons.length} of {visibleLessons.length}
                </span>
              </div>
            </div>

            <div className={styles.list}>
              {filteredLessons.map((lesson) => (
                <button
                  key={lesson.id}
                  type="button"
                  className={`${styles.lessonCard} ${selectedLesson?.id === lesson.id ? styles.lessonCardActive : ''}`}
                  onClick={() => setSelectedLessonId(lesson.id)}
                >
                  <div className={styles.lessonCardInner}>
                    <div className={styles.lessonIconWrap}>
                      <span className={styles.lessonIconBadge}>
                        <BookOpen size={18} strokeWidth={2} />
                      </span>
                    </div>
                    <div className={styles.lessonMain}>
                      <div className={styles.lessonTitleRow}>
                        <h3 className={styles.lessonTitle}>{lesson.title}</h3>
                        <span
                          className={`${styles.statusPill} ${lesson.status === 'planned' ? styles.statusPlanned : ''} ${lesson.status === 'completed' ? styles.statusCompleted : ''} ${lesson.status === 'cancelled' ? styles.statusCancelled : ''}`}
                        >
                          {statusLabel(lesson.status)}
                        </span>
                      </div>
                      <div className={styles.lessonMetaRow}>
                        <span className={styles.metaItem}>
                          <Calendar size={14} aria-hidden />
                          {formatShortDate(lesson.date)}
                        </span>
                        <span className={styles.metaItem}>
                          <Clock size={14} aria-hidden />
                          {lesson.startTime}–{lesson.endTime} · {lesson.duration} min
                        </span>
                        <span className={styles.metaItem}>
                          <Users size={14} aria-hidden />
                          {lesson.teacherName}
                          <span className={styles.metaSep}>·</span>
                          {lesson.studentName}
                        </span>
                      </div>
                    </div>
                    <div className={styles.lessonAside}>
                      <span className={styles.quickActions} aria-hidden>
                        <span className={styles.quickActionBtn}>
                          <Video size={16} />
                        </span>
                        <ChevronRight size={20} className={styles.chevron} />
                      </span>
                      <Link
                        href={`/lessons/${lesson.id}`}
                        className={styles.openLink}
                        onClick={(event) => event.stopPropagation()}
                      >
                        Open
                      </Link>
                    </div>
                  </div>
                </button>
              ))}
              {filteredLessons.length === 0 ? (
                <div className={styles.empty}>No lessons match your filters.</div>
              ) : null}
            </div>
          </SurfaceCard>
        </div>

        <SurfaceCard className={styles.detailPane}>
          {selectedLesson ? (
            <>
              <div className={styles.detailHero}>
                <div className={styles.detailHeroIcon}>
                  <BookOpen size={22} strokeWidth={2} />
                </div>
                <div className={styles.detailHeroText}>
                  <div className={styles.detailHeroTop}>
                    <h2 className={styles.detailHeadline}>{selectedLesson.title}</h2>
                    <span
                      className={`${styles.statusPill} ${selectedLesson.status === 'planned' ? styles.statusPlanned : ''} ${selectedLesson.status === 'completed' ? styles.statusCompleted : ''} ${selectedLesson.status === 'cancelled' ? styles.statusCancelled : ''}`}
                    >
                      {statusLabel(selectedLesson.status)}
                    </span>
                  </div>
                  <p className={styles.detailLede}>
                    {selectedLesson.notes || 'Lesson overview — open the full page for materials and homework.'}
                  </p>
                </div>
              </div>

              <div className={styles.quickStats}>
                <div className={styles.statTile}>
                  <span className={styles.statLabel}>When</span>
                  <span className={styles.statValue}>
                    {formatShortDate(selectedLesson.date)} · {selectedLesson.startTime}
                  </span>
                </div>
                <div className={styles.statTile}>
                  <span className={styles.statLabel}>Duration</span>
                  <span className={styles.statValue}>{selectedLesson.duration} minutes</span>
                </div>
                <div className={styles.statTile}>
                  <span className={styles.statLabel}>People</span>
                  <span className={styles.statValue}>
                    {selectedLesson.teacherName}
                    <span className={styles.statSep}> / </span>
                    {selectedLesson.studentName}
                  </span>
                </div>
              </div>

              <div className={styles.detailBody}>
                <section className={styles.detailSection}>
                  <h4 className={styles.detailSectionTitle}>Lesson plan / notes</h4>
                  <p className={styles.detailSectionText}>
                    {selectedLesson.lessonPlan || selectedLesson.notes || 'No lesson notes yet.'}
                  </p>
                </section>
                <section className={styles.detailSection}>
                  <h4 className={styles.detailSectionTitle}>Homework</h4>
                  <p className={styles.detailSectionText}>
                    {selectedLesson.homework?.text || 'No homework assigned.'}
                  </p>
                </section>
              </div>

              <div className={styles.detailActions}>
                <Link href={`/lessons/${selectedLesson.id}`} className={styles.btnPrimary}>
                  Open lesson page
                </Link>
                <Link href="/calendar" className={styles.btnGhost}>
                  Calendar
                </Link>
              </div>
            </>
          ) : (
            <div className={styles.emptyLarge}>
              <div className={styles.emptyIllustration} aria-hidden />
              <p className={styles.emptyTitle}>Pick a lesson</p>
              <p className={styles.emptyHint}>Select a card on the left to preview details here.</p>
            </div>
          )}
        </SurfaceCard>
      </div>
    </div>
  );
}
